#!/bin/bash\n# send-to-discord.sh - Envía mensajes a Discord\n# Uso: send-to-discord.sh \"Título\" \"Contenido\"\n#      o: echo \"contenido\" | send-to-discord.sh\n\nset -e\n\n# Cargar variables de entorno\nif [ -f \"$HOME/.openclaw/.env\" ]; then\n    export $(grep -v '^#' \"$HOME/.openclaw/.env\" | xargs)\nfi\n\nBOT_TOKEN=\"${DISCORD_BOT_TOKEN}\"\nCHANNEL_ID=\"${DISCORD_CHANNEL_ID}\"\n\nif [ -z \"$BOT_TOKEN\" ] || [ -z \"$CHANNEL_ID\" ]; then\n    echo \"❌ Error: DISCORD_BOT_TOKEN o DISCORD_CHANNEL_ID no configurados\"\n    exit 1\nfi\n\nAPI_URL=\"https://discord.com/api/v10/channels/$CHANNEL_ID/messages\"\n\n# Función para enviar mensaje simple a Discord\nsend_message() {\n    local titulo=\"$1\"\n    local contenido=\"$2\"\n    \n    # Escapar comillas en JSON\n    contenido=$(echo \"$contenido\" | sed 's/\"/\\\\\"/' | sed ':a;N;$!ba;s/\\n/\\\\n/g')\n    \n    # Crear payload JSON\n    local payload=$(cat <<EOF\n{\n    \"content\": \"📊 **$titulo**\\\\n\\\\n$contenido\"\n}\nEOF\n    )\n    \n    # Enviar a Discord\n    local response=$(curl -s -X POST \"$API_URL\" \\\n        -H \"Authorization: Bot $BOT_TOKEN\" \\\n        -H \"Content-Type: application/json\" \\\n        -d \"$payload\")\n    \n    # Validar respuesta\n    if echo \"$response\" | grep -q '\"id\"'; then\n        echo \"✅ Mensaje enviado a Discord\"\n        return 0\n    else\n        echo \"❌ Error enviando a Discord: $response\"\n        return 1\n    fi\n}\n\n# Procesamiento de argumentos\nif [ $# -ge 2 ]; then\n    # Uso: send-to-discord.sh \"Título\" \"Contenido\"\n    titulo=\"$1\"\n    shift\n    contenido=\"$@\"\n    send_message \"$titulo\" \"$contenido\"\nelif [ $# -eq 1 ]; then\n    # Uso: send-to-discord.sh \"archivo.txt\"\n    if [ -f \"$1\" ]; then\n        contenido=$(cat \"$1\")\n        titulo=$(basename \"$1\")\n        send_message \"$titulo\" \"$contenido\"\n    else\n        send_message \"Mensaje\" \"$1\"\n    fi\nelse\n    # Leer de stdin\n    contenido=$(cat)\n    if [ -z \"$contenido\" ]; then\n        echo \"❌ No hay contenido para enviar\"\n        exit 1\n    fi\n    send_message \"Informe\" \"$contenido\"\nfi\n"}}]